     1→import { NextResponse } from "next/server";
     2→import Stripe from "stripe";
     3→
     4→export async function POST() {
     5→  const secretKey = process.env.STRIPE_SECRET_KEY;
     6→
     7→  if (!secretKey) {
     8→    return NextResponse.json(
     9→      { error: "Stripe is not configured. Add STRIPE_SECRET_KEY to .env.local" },
    10→      { status: 500 }
    11→    );
    12→  }
    13→
    14→  try {
    15→    const stripe = new Stripe(secretKey);
    16→
    17→    const paymentIntent = await stripe.paymentIntents.create({
    18→      amount: 999,
    19→      currency: "usd",
    20→      automatic_payment_methods: { enabled: true },
    21→      metadata: { type: "subscription_demo" },
    22→    });
    23→
    24→    return NextResponse.json({ clientSecret: paymentIntent.client_secret });
    25→  } catch (err) {
    26→    const message = err instanceof Error ? err.message : "Unknown error";
    27→    return NextResponse.json({ error: message }, { status: 500 });
    28→  }
    29→}
    30→

