     1→import { client } from "./client";
     2→import { Post } from "@types";
     3→
     4→const POSTS_QUERY = `*[_type == "post"] | order(publishedAt desc) {
     5→  _id,
     6→  title,
     7→  slug,
     8→  excerpt,
     9→  featuredImage,
    10→  "author": author->{_id, name, slug, avatar, bio},
    11→  publishedAt,
    12→  isPremium,
    13→  body
    14→}`;
    15→
    16→const POST_BY_SLUG_QUERY = `*[_type == "post" && slug.current == $slug][0] {
    17→  _id,
    18→  title,
    19→  slug,
    20→  excerpt,
    21→  featuredImage,
    22→  "author": author->{_id, name, slug, avatar, bio},
    23→  publishedAt,
    24→  isPremium,
    25→  body
    26→}`;
    27→
    28→export async function getPosts(): Promise<Post[]> {
    29→  if (!client) return [];
    30→  return client.fetch(POSTS_QUERY);
    31→}
    32→
    33→export async function getPostBySlug(slug: string): Promise<Post | null> {
    34→  if (!client) return null;
    35→  return client.fetch(POST_BY_SLUG_QUERY, { slug });
    36→}
